import React, { useState } from 'react';
import { useI18n } from '../i18n/I18nContext';

const WaitingRoom = ({ gameId, roomPassword, handleBackToMenu, timeLimit }) => {
    const { t } = useI18n();
    const [copied, setCopied] = useState(null);

    const copyWith = (text, label) => {
        if (navigator.clipboard?.writeText) {
            navigator.clipboard.writeText(text).then(() => {
                setCopied(label);
                setTimeout(() => setCopied(null), 2000);
            }).catch(() => {
                // Fallback for non-HTTPS contexts
                try {
                    const ta = document.createElement('textarea');
                    ta.value = text;
                    ta.style.position = 'fixed';
                    ta.style.opacity = '0';
                    document.body.appendChild(ta);
                    ta.select();
                    document.execCommand('copy');
                    document.body.removeChild(ta);
                    setCopied(label);
                    setTimeout(() => setCopied(null), 2000);
                } catch (_) {}
            });
        }
    };

    return (
        <div className="max-w-sm mx-auto pt-4 text-center space-y-5 animate-fade-in">
            {/* ── Room code focal card with corner brackets + scanline ── */}
            <div className="glass-card corner-brackets px-6 py-6 relative overflow-hidden border-yellow-400/40">
                <div className="scanline-sweep" />
                <div className="absolute inset-0 bg-gradient-to-br from-yellow-500/5 via-transparent to-yellow-500/5 pointer-events-none" />
                <div className="relative space-y-2">
                    <p className="text-[0.6rem] text-yellow-400/80 uppercase tracking-[0.3em] font-bold">{t('waiting.roomCode')}</p>
                    <p
                        className="text-4xl sm:text-5xl font-black font-mono text-yellow-300 tracking-[0.2em] drop-shadow-lg"
                        style={{ textShadow: '0 0 24px rgba(253,224,71,0.35)' }}
                    >
                        {gameId}
                    </p>
                    <div className="flex items-center justify-center gap-3 mt-2 flex-wrap">
                        {roomPassword && (
                            <span className="text-xs text-orange-300 bg-orange-500/10 rounded-full py-1 px-3 border border-orange-500/20">
                                🔒 PIN: <span className="font-mono font-bold">{roomPassword}</span>
                            </span>
                        )}
                        {timeLimit && (
                            <span className="text-xs text-blue-300 bg-blue-500/10 rounded-full py-1 px-3 border border-blue-500/20">
                                ⏱️ {Math.round(timeLimit / 60)} {t('waiting.minGame')}
                            </span>
                        )}
                    </div>
                </div>
            </div>

            {/* ── Player slots ── */}
            <div className="grid grid-cols-2 gap-3">
                {/* You */}
                <div className="glass-card slot-ready p-4 space-y-2">
                    <div className="w-10 h-10 mx-auto rounded-full bg-emerald-500/15 flex items-center justify-center text-lg border border-emerald-500/30">
                        ✓
                    </div>
                    <p className="text-sm font-bold text-emerald-300 truncate">{t('waiting.you') || 'You'}</p>
                    <p className="text-[0.6rem] text-emerald-400/60 uppercase tracking-widest">{t('waiting.ready') || 'Ready'}</p>
                </div>
                {/* Opponent */}
                <div className="glass-card slot-waiting p-4 space-y-2">
                    <div className="w-10 h-10 mx-auto rounded-full bg-blue-500/10 flex items-center justify-center border border-blue-500/20">
                        <span className="flex gap-0.5">
                            {[0, 120, 240].map(d => (
                                <span key={d} className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: `${d}ms` }} />
                            ))}
                        </span>
                    </div>
                    <p className="text-sm font-bold text-slate-400 truncate">{t('waiting.waitingFor') || 'Waiting...'}</p>
                    <p className="text-[0.6rem] text-slate-500 uppercase tracking-widest">{t('waiting.notJoined') || 'Not joined'}</p>
                </div>
            </div>

            {/* ── Share title ── */}
            <div>
                <h2 className="text-lg font-bold text-white">{t('waiting.title')}</h2>
                <p className="text-slate-400 text-xs mt-1">{t('waiting.shareHint')}</p>
            </div>

            {/* ── Copy buttons ── */}
            <div className="flex gap-2 justify-center flex-wrap">
                <button
                    onClick={() => copyWith(gameId, 'code')}
                    className={`px-5 py-2.5 text-sm rounded-xl transition font-semibold ${copied === 'code' ? 'bg-green-600 text-white shadow-green-900/30 shadow-md' : 'glass-card !rounded-xl hover:border-slate-500/30 text-slate-200 hover:scale-[1.02]'}`}
                >
                    {copied === 'code' ? '✓ ' + t('waiting.copied') : '📋 ' + t('waiting.copyCode')}
                </button>
                <button
                    onClick={() => {
                        const path = roomPassword ? `${gameId}/${roomPassword}` : gameId;
                        const url = `${window.location.origin}/${path}`;
                        copyWith(url, 'link');
                    }}
                    className={`px-5 py-2.5 text-sm rounded-xl transition font-semibold ${copied === 'link' ? 'bg-green-600 text-white shadow-green-900/30 shadow-md' : 'bg-blue-600/90 hover:bg-blue-500 text-white hover:scale-[1.02] shadow-lg shadow-blue-900/30'}`}
                >
                    {copied === 'link' ? '✓ ' + t('waiting.copied') : `🔗 ${t('waiting.copyLink')}${roomPassword ? ` ${t('waiting.plusPin')}` : ''}`}
                </button>
            </div>

            {/* ── Leave button ── */}
            <button
                onClick={handleBackToMenu}
                className="mt-2 px-6 py-2 text-red-400/80 hover:text-red-300 text-sm font-semibold transition"
            >
                ← {t('waiting.leaveRoom')}
            </button>
        </div>
    );
};

export default WaitingRoom;
